league_hidden_state.script:
storage.guilds = storage.guilds || {}
const league = storage.guilds.league
if (!league || !league.member) { skip = true }

if (!skip) {
  const rankNames = { copper: 'Copper', bronze: 'Bronze', silver: 'Silver', gold: 'Gold' }
  const nextRanks = { copper: 'Bronze', bronze: 'Silver', silver: 'Gold' }
  const requirements = { copper: 2, bronze: 3, silver: 4 }
  const rank = rankNames[league.rank] || league.rank
  const next = nextRanks[league.rank]
  const needed = requirements[league.rank]
  const progress = next ? league.contractCredits + ' of ' + needed + ' recognized contract credits toward ' + next : 'no further standard rank progression'

  effects.push({ type: 'story', instruction: 'Hidden League state: the party is a member of the League of Adventurers. Their current League rank is ' + rank + '. Their current advancement progress is ' + progress + '. This is true world state and should not be contradicted. Do not assume every NPC knows this unless the party presents credentials, the NPC belongs to the League, or the context makes their membership known.' })
}

league_contract_credit_awarded.script:
storage.guilds = storage.guilds || {}
const league = storage.guilds.league
if (!league || !league.member) { skip = true }

const tick = check({ type: 'game-tick' })
if (!skip && tick - (league.lastCreditTick || -999) <= 1) { skip = true }

if (!skip) {
  league.contractCredits = (league.contractCredits || 0) + 1
  league.lastCreditTick = tick
}

league_status_request.script:
storage.guilds = storage.guilds || {}
const league = storage.guilds.league
if (!league || !league.member) {
  effects.push({ type: 'story', instruction: 'IF the player asks about League standing, make clear that the party is not currently registered as members of the League of Adventurers. Disregard this instruction if the player is not asking about League standing.' })
} else {
  const rankNames = { copper: 'Copper', bronze: 'Bronze', silver: 'Silver', gold: 'Gold' }
  const nextRanks = { copper: 'Bronze', bronze: 'Silver', silver: 'Gold' }
  const requirements = { copper: 2, bronze: 3, silver: 4 }
  const rank = rankNames[league.rank] || league.rank
  const next = nextRanks[league.rank]
  const needed = requirements[league.rank]

  if (next && needed) {
    effects.push({ type: 'story', instruction: 'IF the scene allows the party to learn their League standing, state clearly that they are ' + rank + ' rank with ' + league.contractCredits + ' of ' + needed + ' recognized contract credits toward ' + next + ' rank. To advance, they must complete enough League-recognized contracts and then request promotion from a League registrar, ranking officer, or authorized chapterhouse representative. Disregard this instruction if the player is not asking about League standing.' })
  } else {
    effects.push({ type: 'story', instruction: 'IF the scene allows the party to learn their League standing, state clearly that they are ' + rank + ' rank. There is no further standard League advancement currently tracked. Disregard this instruction if the player is not asking about League standing.' })
  }
}

league_promotion_request.script:
storage.guilds = storage.guilds || {}
const league = storage.guilds.league
if (!league || !league.member) {
  effects.push({ type: 'story', instruction: 'IF the player requests League promotion, the party is not currently registered as members of the League of Adventurers, so a League official should not grant rank advancement. They must join first. Disregard this instruction if the player is not requesting League promotion.' })
} else {
  const rankNames = { copper: 'Copper', bronze: 'Bronze', silver: 'Silver', gold: 'Gold' }
  const nextRanks = { copper: 'Bronze', bronze: 'Silver', silver: 'Gold' }
  const requirements = { copper: 2, bronze: 3, silver: 4 }
  const rank = rankNames[league.rank] || league.rank
  const next = nextRanks[league.rank]
  const needed = requirements[league.rank]

  if (!next || !needed) {
    effects.push({ type: 'story', instruction: 'IF the player requests League promotion, the party is already at the highest standard League rank currently tracked. A League official should not invent a higher ordinary promotion unless the story has established a special honor. Disregard this instruction if the player is not requesting League promotion.' })
  } else if ((league.contractCredits || 0) >= needed) {
    effects.push({ type: 'story', instruction: 'IF the player requests League promotion, the party meets the League requirements for promotion from ' + rank + ' to ' + next + '. If they are speaking with a League registrar, ranking officer, or authorized chapterhouse representative, that official may formally promote them in this scene. Disregard this instruction if the player is not requesting League promotion.' })
  } else {
    effects.push({ type: 'story', instruction: 'IF the player requests League promotion, the party does not yet meet the League requirements for promotion from ' + rank + ' to ' + next + '. They have ' + league.contractCredits + ' of ' + needed + ' recognized contract credits. A League official may acknowledge their progress, but should not grant the higher rank yet. Disregard this instruction if the player is not requesting League promotion.' })
  }
}

league_capture_copper_to_bronze.script:
