league_rank_contract_scope.script:
storage.guilds = storage.guilds || {}
const league = storage.guilds.league
if (!league || !league.member) { skip = true }

const location = check({ type: 'party-location' }) || ''
const area = check({ type: 'party-area' }) || ''
const inLeagueSpace = location.includes('League Chapterhouse') || area === 'The Tower of Venture'
if (!skip && !inLeagueSpace) { skip = true }

if (!skip) {
  const rank = league.rank || 'copper'
  const instructions = {
    copper: 'The party holds Copper rank in the League of Adventurers, the entry tier. IF contracts are offered, they should be low-stakes proving work: vermin clearances, minor smuggler tips, missing persons, petty criminals, small monsters, local errands, or simple investigations. Rewards are modest. Do not offer Council-sealed work, politically sensitive jobs, or contracts that would send them directly against legendary threats. Disregard this instruction if no League contract is being offered or discussed.',
    bronze: 'The party holds Bronze rank in the League of Adventurers. IF contracts are offered, they may involve named local threats, rescue work, dangerous ruins, organized criminals, minor cult cells, undead outbreaks, monster lairs, and jobs with meaningful local stakes. They are trusted field adventurers, but not elite agents. Disregard this instruction if no League contract is being offered or discussed.',
    silver: 'The party holds Silver rank in the League of Adventurers. IF contracts are offered, they may involve dangerous regional threats, sensitive clients, faction complications, long-distance travel, difficult monsters, and operations tied to larger powers. They are established professionals. Disregard this instruction if no League contract is being offered or discussed.',
    gold: 'The party holds Gold rank in the League of Adventurers. IF contracts are offered, they may involve severe threats, politically sensitive work, powerful monsters, major faction entanglements, crisis-level missions, and Dragon Queen operations of high strategic importance. Disregard this instruction if no League contract is being offered or discussed.'
  }
  effects.push({ type: 'story', instruction: instructions[rank] || instructions.copper })
}

